import React, { useEffect, useRef, useState, useCallback } from "react";
import lottie from "lottie-web";
import { Icon } from "@iconify/react";
import "./FeelingProud.css";

/* ==========================================================
   AI COMMAND CORE — the hero's centerpiece.
   Robot nucleus + three elliptical orbit rings with real
   depth (icons shrink/dim behind the core, grow in front),
   cinematic entrance, cursor parallax, click shockwave.
   ========================================================== */

const FUN_MESSAGES = [
  "👋 Hey! I'm coding something cool!",
  "💻 Let me show you my latest projects",
  "☕ Coffee first, code later!",
  "🚀 Shipping to production…",
];

/* Icons distributed across three rings, inner → outer.
   duration = seconds per revolution; squash = ellipse flatness. */
const RINGS = [
  {
    id: "ring-a",
    radius: 168,
    duration: 22,
    squash: 0.44,
    tilt: -8,
    icons: [
      { name: "React", icon: "logos:react", color: "#61DAFB" },
      { name: "Node.js", icon: "logos:nodejs-icon", color: "#339933" },
      { name: "Python", icon: "logos:python", color: "#3776AB" },
      { name: "Git", icon: "logos:git-icon", color: "#F05032" },
    ],
  },
  {
    id: "ring-b",
    radius: 238,
    duration: 34,
    squash: 0.4,
    tilt: -8,
    icons: [
      { name: "VS Code", icon: "vscode-icons:file-type-vscode", color: "#007ACC" },
      { name: "Docker", icon: "logos:docker-icon", color: "#2496ED" },
      { name: "GitHub", icon: "skill-icons:github-dark", color: "#8b949e" },
      { name: "Google Cloud", icon: "logos:google-cloud", color: "#4285F4" },
    ],
  },
  {
    id: "ring-c",
    radius: 305,
    duration: 48,
    squash: 0.36,
    tilt: -8,
    icons: [
      { name: "npm", icon: "logos:npm-icon", color: "#CB3837" },
      { name: "Terminal", icon: "vscode-icons:file-type-shell", color: "#4EAA25" },
      { name: "Anthropic", icon: "simple-icons:anthropic", color: "#D97757" },
    ],
  },
];

function FeelingProud(props) {
  const theme = props.theme;
  const robotRef = useRef(null);
  const sceneRef = useRef(null);
  const animationRef = useRef(null);
  const rafRef = useRef(null);

  const [showMessage, setShowMessage] = useState(false);
  const [currentMessage, setCurrentMessage] = useState("");
  const [pulseKey, setPulseKey] = useState(0);
  const [hasInteracted, setHasInteracted] = useState(false);

  /* Robot lottie */
  useEffect(() => {
    if (!robotRef.current) return;
    animationRef.current = lottie.loadAnimation({
      container: robotRef.current,
      renderer: "svg",
      loop: true,
      autoplay: true,
      path: "https://assets2.lottiefiles.com/packages/lf20_ofa3xwo7.json",
    });
    return () => animationRef.current && animationRef.current.destroy();
  }, []);

  /* Cursor parallax — the whole core leans toward the mouse */
  const handleMouseMove = useCallback((e) => {
    if (rafRef.current) return;
    rafRef.current = requestAnimationFrame(() => {
      rafRef.current = null;
      const scene = sceneRef.current;
      if (!scene) return;
      const rect = scene.parentElement.getBoundingClientRect();
      const px = ((e.clientX - rect.left) / rect.width - 0.5) * 2;
      const py = ((e.clientY - rect.top) / rect.height - 0.5) * 2;
      scene.style.setProperty("--px", px.toFixed(3));
      scene.style.setProperty("--py", py.toFixed(3));
    });
  }, []);

  const handleMouseLeave = useCallback(() => {
    const scene = sceneRef.current;
    if (!scene) return;
    scene.style.setProperty("--px", "0");
    scene.style.setProperty("--py", "0");
  }, []);

  useEffect(() => {
    return () => rafRef.current && cancelAnimationFrame(rafRef.current);
  }, []);

  /* Click: message + shockwave + brief speed-up */
  const handleClick = () => {
    setHasInteracted(true);
    setCurrentMessage(
      FUN_MESSAGES[Math.floor(Math.random() * FUN_MESSAGES.length)]
    );
    setShowMessage(true);
    setPulseKey((k) => k + 1);

    if (animationRef.current) {
      animationRef.current.setSpeed(2);
      setTimeout(
        () => animationRef.current && animationRef.current.setSpeed(1),
        1000
      );
    }
    setTimeout(() => setShowMessage(false), 3000);
  };

  const handleDoubleClick = () => {
    if (!animationRef.current) return;
    animationRef.current.setDirection(-1);
    animationRef.current.play();
    setTimeout(
      () => animationRef.current && animationRef.current.setDirection(1),
      2000
    );
  };

  return (
    <div
      className="hero-core"
      style={{ "--core-accent": theme.accentColor }}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
    >
      {/* ambient aurora + spotlight behind everything */}
      <div className="core-aurora" aria-hidden="true" />

      <div className="core-scene" ref={sceneRef}>
        {/* entrance / click shockwave */}
        <div className="core-shockwave" key={pulseKey} aria-hidden="true" />

        {/* orbit rings */}
        {RINGS.map((ring, r) => (
          <div
            key={ring.id}
            className={`core-ring ${ring.id}`}
            style={{
              "--ring-r": `${ring.radius}px`,
              "--ring-d": `${ring.radius * 2}px`,
              "--squash": ring.squash,
              "--unsquash": (1 / ring.squash).toFixed(3),
              "--tilt": `${ring.tilt}deg`,
              "--untilt": `${-ring.tilt}deg`,
              "--ring-delay": `${0.55 + r * 0.18}s`,
            }}
            aria-hidden="true"
          >
            {ring.icons.map((tool, i) => (
              <div
                key={tool.name}
                className="core-orbiter"
                style={{
                  "--orbit-dur": `${ring.duration}s`,
                  "--orbit-delay": `${(-i * ring.duration) / ring.icons.length}s`,
                  "--angle": `${(i * 360) / ring.icons.length}deg`,
                }}
              >
                <div className="core-counter">
                  <div className="core-depth">
                    <div
                      className="core-chip"
                      title={tool.name}
                      style={{ "--chip-color": tool.color }}
                    >
                      <Icon icon={tool.icon} className="core-chip-icon" />
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ))}

        {/* the robot nucleus */}
        <div className="core-robot-wrap">
          <div
            className="core-robot"
            ref={robotRef}
            onClick={handleClick}
            onDoubleClick={handleDoubleClick}
            role="button"
            aria-label="Interactive robot — tap for a message"
          />
          {showMessage && (
            <div className="core-bubble">
              {currentMessage}
              <span className="core-bubble-tail" />
            </div>
          )}
        </div>

        {/* glow pad under the robot */}
        <div className="core-basepad" aria-hidden="true" />
      </div>

      {!hasInteracted && (
        <button
          type="button"
          className="core-hint"
          onClick={handleClick}
          aria-hidden="true"
          tabIndex={-1}
        >
          ✨ tap
        </button>
      )}
    </div>
  );
}

export default FeelingProud;
